// ============================================================
// Transformer credentials Airtable → format PostgreSQL
// ============================================================

const items = $input.all();
let migrated = 0;
let skipped = 0;

const results = items
  .map((it, idx) => {
    const r = it.json;
    const f = r.fields || r;

    // Ignorer les records vides
    if (!f.credential_ref) {
      skipped++;
      return null;
    }

    migrated++;

    return {
      json: {
        credential_ref: f.credential_ref,
        client_id: f.client_id || 0,
        platform: (f.platform || '').toLowerCase(),
        access_token: f.access_token || '',
        refresh_token: f.refresh_token || null,
        client_app_id: f.client_app_id || null,
        client_secret: f.client_secret || null,
        expires_at: f.expires_at || null,
        created_at: f.created_at || new Date().toISOString(),
        updated_at: f.updated_at || new Date().toISOString(),
      },
      pairedItem: { item: idx },
    };
  })
  .filter(Boolean);

if (results.length === 0) {
  return [{ json: { _status: 'SKIP', _message: 'Aucun credential à migrer', _migrated: 0, _skipped: skipped } }];
}

console.log(`Credentials: ${migrated} à migrer, ${skipped} ignorés`);
return results;

// Compteur credentials migrés
const items = $input.all();
const inserted = items.filter(i => i.json?.credential_ref).length;
const total = items.length;

return [{
  json: {
    step: 'CREDENTIALS',
    status: 'DONE',
    inserted,
    total,
    message: `✅ ${inserted}/${total} credentials migrés vers PostgreSQL`
  }
}];

// ============================================================
// Transformer diffusion_jobs Airtable → format PostgreSQL
// ============================================================
// Conversions clés :
//   - payload : string → JSONB (parse si nécessaire)
//   - last_error : string → JSONB
//   - diffusion_id : float → bigint
//   - budget_amount : number → numeric
//   - empty strings → null (pour les colonnes nullable)
// ============================================================

const items = $input.all();
let migrated = 0;
let skipped = 0;

const results = items
  .map((it, idx) => {
    const r = it.json;
    const f = r.fields || r;

    if (!f.job_id) {
      skipped++;
      return null;
    }

    migrated++;

    // Parse payload en objet si c'est un string
    let payload = f.payload || '{}';
    if (typeof payload === 'string') {
      try { payload = JSON.parse(payload); } catch(e) { payload = {}; }
    }

    // Parse last_error en objet si c'est un string
    let last_error = f.last_error || null;
    if (typeof last_error === 'string' && last_error.trim()) {
      try { last_error = JSON.parse(last_error); } catch(e) {
        last_error = { raw_message: last_error };
      }
    }

    // Nettoyer les empty strings → null
    const clean = (v) => (v === '' || v === undefined) ? null : v;

    // Nettoyer le statut (trim les espaces — ex: 'FAILED_LLM ' dans Airtable)
    const status = (f.status || 'RECEIVED').trim();

    return {
      json: {
        job_id: f.job_id,
        request_id: f.request_id || '',
        batch_id: f.batch_id || '',
        diffusion_id: f.diffusion_id ? Math.floor(f.diffusion_id) : null,
        source_agent: f.source_agent || 'AGENT_ADS',
        client_id: f.client_id || 0,
        campaign_id: f.campaign_id ? Math.floor(f.campaign_id) : null,
        channel_name: (f.channel_name || '').toUpperCase(),
        credential_ref: f.credential_ref || '',
        diffusion_type: (f.diffusion_type || 'ORGANIC').toUpperCase(),
        funnel_stage: clean(f.funnel_stage),
        scheduled_at: clean(f.scheduled_at),
        timezone: f.timezone || 'Africa/Casablanca',
        budget_amount: f.budget_amount || null,
        budget_currency: clean(f.budget_currency),
        payload: JSON.stringify(payload),
        status,
        retry_count: f.retry_count || 0,
        retry_max: f.retry_max || 3,
        platform_post_id: clean(f.platform_post_id),
        last_error: last_error ? JSON.stringify(last_error) : null,
        created_at: f.created_at || new Date().toISOString(),
        updated_at: f.updated_at || new Date().toISOString(),
      },
      pairedItem: { item: idx },
    };
  })
  .filter(Boolean);

if (results.length === 0) {
  return [{ json: { _status: 'SKIP', _message: 'Aucun job à migrer', _migrated: 0, _skipped: skipped } }];
}

console.log(`Jobs: ${migrated} à migrer, ${skipped} ignorés`);
return results;

// Compteur jobs migrés
const items = $input.all();
const inserted = items.filter(i => i.json?.job_id).length;
const errors = items.filter(i => i.json?.error).length;
const total = items.length;

return [{
  json: {
    step: 'DIFFUSION_JOBS',
    status: 'DONE',
    inserted,
    errors,
    total,
    message: `✅ ${inserted}/${total} jobs migrés vers PostgreSQL${errors ? ` (${errors} erreurs)` : ''}`
  }
}];

// ============================================================
// Transformer log_events Airtable → format PostgreSQL
// ============================================================
// Les logs vont automatiquement dans la bonne partition
// mensuelle grâce au partitionnement par timestamp.
// ============================================================

const items = $input.all();
let migrated = 0;
let skipped = 0;

const results = items
  .map((it, idx) => {
    const r = it.json;
    const f = r.fields || r;

    if (!f.log_id && !f.event_type) {
      skipped++;
      return null;
    }

    migrated++;

    // Si pas de log_id, en générer un
    let log_id = f.log_id;
    if (!log_id) {
      const hex = Array.from({ length: 6 }, () =>
        Math.floor(Math.random() * 16).toString(16).toUpperCase()
      ).join('');
      log_id = `LOG-MIGR-${hex}`;
    }

    // Timestamp : utiliser celui d'Airtable ou le created_at
    const timestamp = f.timestamp || f.created_at || new Date().toISOString();

    return {
      json: {
        log_id,
        job_id: f.job_id || null,
        correlation_id: f.correlation_id || null,
        agent: f.agent || 'SYSTEM',
        event_type: f.event_type || 'UNKNOWN',
        message: f.message || '',
        timestamp,
      },
      pairedItem: { item: idx },
    };
  })
  .filter(Boolean);

if (results.length === 0) {
  return [{ json: { _status: 'SKIP', _message: 'Aucun log à migrer', _migrated: 0, _skipped: skipped } }];
}

console.log(`Logs: ${migrated} à migrer, ${skipped} ignorés`);
return results;

// Compteur logs migrés
const items = $input.all();
const inserted = items.filter(i => i.json?.log_id).length;
const total = items.length;

return [{
  json: {
    step: 'LOG_EVENTS',
    status: 'DONE',
    inserted,
    total,
    message: `✅ ${inserted}/${total} logs migrés vers PostgreSQL`
  }
}];

// ============================================================
// Rapport final de migration
// ============================================================

const credResult = $items('Log — Credentials migrés')[0]?.json || {};
const jobResult = $items('Log — Jobs migrés')[0]?.json || {};
const logResult = $items('Log — Logs migrés')[0]?.json || {};

const report = {
  migration_completed_at: new Date().toISOString(),
  results: [
    credResult,
    jobResult,
    logResult,
  ],
  summary: [
    credResult.message || 'Credentials: non exécuté',
    jobResult.message || 'Jobs: non exécuté',
    logResult.message || 'Logs: non exécuté',
  ].join('\n'),
  next_steps: [
    '1. Vérifier les données dans pgAdmin (http://localhost:5050)',
    '2. Configurer le credential PostgreSQL dans n8n',
    '3. Importer les 4 workflows v2',
    '4. Tester chaque service indépendamment',
    '5. Désactiver les anciens workflows Airtable',
  ],
};

return [{ json: report }];
